#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 10000

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to find the LCA of two nodes
Node* findLCA(Node* root, int X, int Y) {
    if (root == NULL) return NULL;
    if (root->val > X && root->val > Y) return findLCA(root->left, X, Y);
    if (root->val < X && root->val < Y) return findLCA(root->right, X, Y);
    return root;
}

int main() {
    int N, X, Y;
    scanf("%d %d %d", &N, &X, &Y);
    Node* root = NULL;
    Node* nodes[MAX];
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(i+1);
    }
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);
        if (Ri == 'L') {
            nodes[pi-1]->left = nodes[ci-1];
        } else {
            nodes[pi-1]->right = nodes[ci-1];
        }
    }
    root = nodes[0];
    Node* lca = findLCA(root, X, Y);
    printf("%d\n", lca->val);
    return 0;
}

