const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
function readline() {
    return lines[i++];
}

class Node {
    constructor(val) {
        this.val = val;
        this.left = null;
        this.right = null;
    }
}

function findLCA(root, X, Y) {
    if (root === null) return null;
    if (root.val > X && root.val > Y) return findLCA(root.left, X, Y);
    if (root.val < X && root.val < Y) return findLCA(root.right, X, Y);
    return root;
}

function main() {
    let [N, X, Y] = readline().split(' ').map(Number);
    let nodes = Array(N).fill(0).map((_, i) => new Node(i+1));
    for (let i = 0; i < N - 1; i++) {
        let [pi, ci, Ri] = readline().split(' ');
        pi = parseInt(pi);
